import { ref, watch } from 'vue'

const STORAGE_KEY = 'contacts'

export function useContacts() {
  const contacts = ref([])

  // Загрузка из localStorage при инициализации
  const loadFromStorage = () => {
    const stored = localStorage.getItem(STORAGE_KEY)
    if (stored) {
      contacts.value = JSON.parse(stored)
    }
  }

  // Сохранение в localStorage при изменениях
  const saveToStorage = () => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(contacts.value))
  }

  // Watch для автосохранения
  watch(contacts, saveToStorage, { deep: true })

  // CRUD операции
  const addContact = (contactData) => {
    const contact = {
      id: crypto.randomUUID(),
      ...contactData,
      createdAt: new Date().toISOString()
    }
    contacts.value.push(contact)
    return contact
  }

  const updateContact = (id, data) => {
    const index = contacts.value.findIndex(c => c.id === id)
    if (index !== -1) {
      contacts.value[index] = { ...contacts.value[index], ...data }
    }
  }

  const deleteContact = (id) => {
    contacts.value = contacts.value.filter(c => c.id !== id)
  }

  const searchContacts = (query) => {
    const q = query.toLowerCase()
    return contacts.value.filter(c =>
      c.name.toLowerCase().includes(q) ||
      c.email.toLowerCase().includes(q)
    )
  }

  const filterByGroup = (group) => {
    if (!group) return contacts.value
    return contacts.value.filter(c => c.group === group)
  }

  // Инициализация
  loadFromStorage()

  return {
    contacts,
    addContact,
    updateContact,
    deleteContact,
    searchContacts,
    filterByGroup
  }
}

import { mount } from '@vue/test-utils'
import SearchBar from '../../src/components/SearchBar.vue'

describe('SearchBar', () => {
  it('imports without errors', () => {
    expect(SearchBar).toBeDefined()
  })

  it('mounts without props', () => {
    const wrapper = mount(SearchBar)
    expect(wrapper.exists()).toBe(true)
  })

  it('defines groups prop as Array with default value', () => {
    const groupsProp = SearchBar.props.groups
    expect(groupsProp.type).toBe(Array)
    expect(groupsProp.default()).toEqual(['Семья', 'Друзья', 'Работа', 'Другое'])
  })

  it('defines search and filter emits', () => {
    expect(SearchBar.emits).toContain('search')
    expect(SearchBar.emits).toContain('filter')
  })

  it('renders root element with search-bar class', () => {
    const wrapper = mount(SearchBar)
    expect(wrapper.find('.search-bar').exists()).toBe(true)
  })

  it('renders search input', () => {
    const wrapper = mount(SearchBar)
    const searchInput = wrapper.find('#search')
    expect(searchInput.exists()).toBe(true)
    expect(searchInput.attributes('placeholder')).toBe('Поиск по имени или email...')
  })

  it('renders group filter select', () => {
    const wrapper = mount(SearchBar)
    const groupSelect = wrapper.find('#group-filter')
    expect(groupSelect.exists()).toBe(true)
  })

  it('renders all default groups as options', () => {
    const wrapper = mount(SearchBar)
    const groupSelect = wrapper.find('#group-filter')
    const options = groupSelect.findAll('option')
    const optionValues = options.map(opt => opt.text())
    expect(optionValues).toContain('Все группы')
    expect(optionValues).toContain('Семья')
    expect(optionValues).toContain('Друзья')
    expect(optionValues).toContain('Работа')
    expect(optionValues).toContain('Другое')
  })

  it('renders custom groups passed as props', () => {
    const customGroups = ['Группа 1', 'Группа 2', 'Группа 3']
    const wrapper = mount(SearchBar, {
      props: {
        groups: customGroups
      }
    })
    const groupSelect = wrapper.find('#group-filter')
    const options = groupSelect.findAll('option')
    const optionValues = options.map(opt => opt.text())
    expect(optionValues).toContain('Все группы')
    expect(optionValues).toContain('Группа 1')
    expect(optionValues).toContain('Группа 2')
    expect(optionValues).toContain('Группа 3')
  })

  it('emits search event when searchQuery changes', async () => {
    const wrapper = mount(SearchBar)
    const searchInput = wrapper.find('#search')
    await searchInput.setValue('Иван')
    expect(wrapper.emitted('search')).toBeTruthy()
    expect(wrapper.emitted('search')).toHaveLength(1)
    expect(wrapper.emitted('search')[0]).toEqual(['Иван'])
  })

  it('emits search event with empty string when input is cleared', async () => {
    const wrapper = mount(SearchBar)
    const searchInput = wrapper.find('#search')
    await searchInput.setValue('Иван')
    await searchInput.setValue('')
    expect(wrapper.emitted('search')).toBeTruthy()
    expect(wrapper.emitted('search')).toHaveLength(2)
    expect(wrapper.emitted('search')[1]).toEqual([''])
  })

  it('emits filter event when selectedGroup changes', async () => {
    const wrapper = mount(SearchBar)
    const groupSelect = wrapper.find('#group-filter')
    await groupSelect.setValue('Друзья')
    expect(wrapper.emitted('filter')).toBeTruthy()
    expect(wrapper.emitted('filter')).toHaveLength(1)
    expect(wrapper.emitted('filter')[0]).toEqual(['Друзья'])
  })

  it('emits filter event with empty string when "Все группы" is selected', async () => {
    const wrapper = mount(SearchBar)
    const groupSelect = wrapper.find('#group-filter')
    await groupSelect.setValue('Друзья')
    await groupSelect.setValue('')
    expect(wrapper.emitted('filter')).toBeTruthy()
    expect(wrapper.emitted('filter')).toHaveLength(2)
    expect(wrapper.emitted('filter')[1]).toEqual([''])
  })

  it('search input value is reactive', async () => {
    const wrapper = mount(SearchBar)
    const searchInput = wrapper.find('#search')
    await searchInput.setValue('test query')
    expect(searchInput.element.value).toBe('test query')
  })

  it('group select value is reactive', async () => {
    const wrapper = mount(SearchBar)
    const groupSelect = wrapper.find('#group-filter')
    await groupSelect.setValue('Работа')
    expect(groupSelect.element.value).toBe('Работа')
  })
})

